*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
  --primary: #6c47ff;
  --primary-dark: #5535e0;
  --bg: #f5f4ff;
  --surface: #ffffff;
  --border: #e0ddf7;
  --text: #1a1535;
  --muted: #8b85aa;
  --danger: #e53e3e;
  --success: #38a169;
  --radius: 12px;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  background: var(--bg);
  color: var(--text);
  min-height: 100vh;
}

header {
  background: var(--primary);
  color: white;
  padding: 20px 0;
  box-shadow: 0 2px 12px rgba(108,71,255,.3);
}

header .inner {
  max-width: 860px;
  margin: 0 auto;
  padding: 0 20px;
  display: flex;
  align-items: center;
  gap: 12px;
}

header h1 { font-size: 1.5rem; font-weight: 700; letter-spacing: -.5px; }
header .logo { font-size: 1.8rem; }

.container {
  max-width: 860px;
  margin: 32px auto;
  padding: 0 20px;
  display: flex;
  flex-direction: column;
  gap: 28px;
}

.card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 28px;
  box-shadow: 0 2px 8px rgba(108,71,255,.06);
}

.card h2 {
  font-size: 1.1rem;
  font-weight: 700;
  margin-bottom: 20px;
  color: var(--primary);
}

.form-row {
  display: grid;
  gap: 14px;
}

.form-group {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

label {
  font-size: .85rem;
  font-weight: 600;
  color: var(--muted);
  text-transform: uppercase;
  letter-spacing: .05em;
}

input[type="text"], input[type="url"], input[type="number"] {
  padding: 11px 14px;
  border: 1.5px solid var(--border);
  border-radius: 8px;
  font-size: .95rem;
  color: var(--text);
  background: var(--bg);
  transition: border-color .2s;
  outline: none;
}

input:focus { border-color: var(--primary); background: #fff; }

.row2 { display: grid; grid-template-columns: 1fr 1fr; gap: 14px; }

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 12px 22px;
  border: none;
  border-radius: 8px;
  font-size: .95rem;
  font-weight: 600;
  cursor: pointer;
  transition: background .2s, transform .1s;
}

.btn:active { transform: scale(.98); }
.btn-primary { background: var(--primary); color: white; }
.btn-primary:hover { background: var(--primary-dark); }
.btn-sm { padding: 6px 12px; font-size: .8rem; border-radius: 6px; }
.btn-danger { background: #fff0f0; color: var(--danger); border: 1px solid #fcc; }
.btn-danger:hover { background: #ffe0e0; }

.result-box {
  margin-top: 18px;
  padding: 16px 18px;
  border-radius: 8px;
  display: none;
}

.result-box.success {
  display: block;
  background: #f0fdf4;
  border: 1.5px solid #86efac;
}

.result-box.error {
  display: block;
  background: #fff5f5;
  border: 1.5px solid #fca5a5;
}

.result-box .label { font-size: .8rem; color: var(--muted); font-weight: 600; margin-bottom: 6px; }

.result-url {
  display: flex;
  align-items: center;
  gap: 10px;
  flex-wrap: wrap;
}

.result-url a {
  color: var(--primary);
  font-weight: 700;
  font-size: 1.05rem;
  text-decoration: none;
  word-break: break-all;
}

.result-url a:hover { text-decoration: underline; }

.copy-btn {
  padding: 5px 12px;
  font-size: .8rem;
  background: var(--primary);
  color: white;
  border: none;
  border-radius: 6px;
  cursor: pointer;
  font-weight: 600;
  transition: background .2s;
  white-space: nowrap;
}

.copy-btn:hover { background: var(--primary-dark); }

.error-msg { color: var(--danger); font-size: .9rem; font-weight: 500; }

/* Table */
.table-wrap { overflow-x: auto; }

table {
  width: 100%;
  border-collapse: collapse;
  font-size: .88rem;
}

thead th {
  background: var(--bg);
  padding: 10px 12px;
  text-align: left;
  font-size: .78rem;
  text-transform: uppercase;
  letter-spacing: .05em;
  color: var(--muted);
  border-bottom: 1.5px solid var(--border);
}

tbody tr { border-bottom: 1px solid var(--border); transition: background .15s; }
tbody tr:hover { background: var(--bg); }
tbody td { padding: 11px 12px; vertical-align: middle; }

.short-link { color: var(--primary); font-weight: 600; text-decoration: none; }
.short-link:hover { text-decoration: underline; }
.original-url { color: var(--muted); max-width: 220px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; display: block; }
.badge { display: inline-block; padding: 3px 8px; border-radius: 20px; font-size: .75rem; font-weight: 600; }
.badge-active { background: #d1fae5; color: #065f46; }
.badge-expired { background: #fee2e2; color: #991b1b; }
.badge-forever { background: #ede9fe; color: #5b21b6; }

.clicks { font-weight: 700; color: var(--primary); }

.empty { text-align: center; padding: 40px; color: var(--muted); font-size: .95rem; }

.refresh-btn { float: right; margin-top: -4px; }

@media (max-width: 600px) {
  .row2 { grid-template-columns: 1fr; }
  header h1 { font-size: 1.2rem; }
}

